export function parseBroker(broker, defaultPort = 9092) {
    if (typeof broker === 'string') {
        if (broker.includes(':')) {
            const [host, port] = broker.split(':');
            return { host, port: Number(port) };
        }
        else {
            return { host: broker, port: defaultPort };
        }
    }
    return broker;
}
